def is_planar_basic_checks(graph):
    n = len(graph)
    if n <= 2:
        return True

    num_edges_sum_degrees = 0
    degrees = {}
    for u, neighbors in graph.items():
        degrees[u] = len(neighbors)
        num_edges_sum_degrees += len(neighbors)

    m = num_edges_sum_degrees // 2

    if m > 3 * n - 6:
        return False

    all_degrees_at_least_6 = True
    for degree in degrees.values():
        if degree < 6:
            all_degrees_at_least_6 = False
            break

    if all_degrees_at_least_6:
        return False

    return True
